{
  "name": "Mississippi State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; prioritizes people with limited incomes but open to all Medicare beneficiaries, families, and caregivers[1][5]",
    "asset_limits": "No asset limits or tests apply[1]",
    "other_requirements": ["Must be a Medicare beneficiary, under 65 with Medicare disability, dually eligible for Medicare/Medicaid, family member, or caregiver[1][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one counseling (in-person/phone), education, assistance with Medicare Parts A/B/C/D, Medigap, Medicare Savings Programs, Extra Help/LIS, Medicaid applications, claims/appeals, fraud prevention (SMP), printed materials, referrals, group presentations, enrollment events[1][3][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-844-822-4622 or 601-709-0624 (M-F 8am-5pm)[5][8]", "Website: Mississippi Department of Human Services SHIP page (via shiphelp.org or mdhs.ms.gov)[5][8]", "In-person: Through MDHS Division of Aging and Adult Services or local networks (contact via phone for appointment)[2][5]"],
    "processing_time": "Immediate counseling assistance available by phone/in-person; no formal processing for enrollment as it's a service program[3][5]",
    "waitlist": null,
    "forms": ["No specific forms required; counselors assist with Medicare/Medicaid/Extra Help applications during sessions[1][5]"],
    "documents": ["Medicare card, current health insurance details, medical bills/EOBs if applicable, income info if applying for savings programs (counselors guide preparation)[3][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all of Mississippi[2]",
    "regional_variations": "Delivered via statewide MDHS administration with local networks, affiliates, Area Agencies on Aging; no specified differences in services/wait times by region[2][5][7]",
    "offices_or_providers": ["Mississippi Department of Human Services, 750 North State Street, Jackson MS 39202 (central office); local sites via community providers[2][5]"]
  },
  "official_source": "https://www.mdhs.ms.gov (Mississippi Department of Human Services) or https://www.shiphelp.org/ships/mississippi/[5][8]",
  "gotchas": ["Not a financial aid or healthcare provider program—only counseling/education, no direct payments or medical services; must be Medicare-related issue; prioritizes limited-income/disabled but serves all; review plans annually during open enrollment (e.g., Oct 15-Dec 7)[1][5]", "Volunteers/staff handle complex appeals but cannot provide legal advice[1][4]"],
  "data_shape_notes": "no income/asset test; counseling-only service via phone/in-person statewide network; prioritizes Medicare navigation and low-income program applications; administered by state aging division with local affiliates[1][2][5]"
}

{
  "name": "State Long Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available regardless of financial status.",
    "asset_limits": "No asset limits; available regardless of financial status.",
    "other_requirements": ["Resides in or is a potential resident of a long-term care facility subject to regulation or licensure by the Mississippi State Department of Health (e.g., nursing homes, personal care homes, assisted living facilities)."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy to resolve complaints and problems; protection of health, safety, welfare, and rights; intervention and representation on behalf of residents; information and assistance; regular visits to facilities; community education; works to improve quality of life and care at individual, local, state, and national levels.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-888-844-0041", "Phone (State Ombudsman): 601-359-4927", "Website: https://www.mdhs.ms.gov/aging/ombudsman/", "Mail/In-person: MDHS, 200 South Lamar St., Jackson, MS 39201"],
    "processing_time": "Timely responses to requests for information and complaints (exact timeline not specified).",
    "waitlist": null,
    "forms": [],
    "documents": ["No specific documents required; contact ombudsman to discuss concerns or complaints."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "All 82 counties in Mississippi.",
    "regional_variations": "Delivered through contracts with Area Agencies on Aging (AAAs); 19 local ombudsmen with 2 staff statewide; may have differences in local staffing, visits, and response based on AAA regions.",
    "offices_or_providers": ["Operated by Mississippi Department of Human Services, Division of Aging & Adult Services (DAAS) via AAAs across the state; main office in Jackson."]
  },
  "official_source": "https://www.mdhs.ms.gov/aging/ombudsman/",
  "gotchas": ["Not a direct service provider (e.g., no financial aid, healthcare, or housing); focuses solely on advocacy and complaint resolution.", "Available to potential residents (pre-admission) as well as current residents.", "Anyone can file a complaint on behalf of a resident; program prioritizes resident's concerns.", "Volunteers must be certified; families cannot become ombudsmen without training."],
  "data_shape_notes": "no income test; open to all regardless of age or finances; advocacy-only (no direct services or benefits); delivered regionally via 19 local ombudsmen through AAAs covering all counties"
}
